  "use strict";

  const Constants = Object.freeze({
    /**
     * The name of the icon rendered in the popup
     * @type {String}
     */
    ANNOTATE_ICON_NAME: "comment",
    /**
     * The keyboard shortcut that needs to be triggered to create an annotation
     * @type {KeyboardEventInit}
     */
    ANNOTATE_SHORTCUT: { ctrlKey: true, keyCode: 77 }, // ShortcutJS still expects the deprecated keyCode property
    /**
     * The translation key for the button title (accessibility)
     * @type {String}
     */
    ANNOTATE_TRANSLATION_KEY: "action.create.submit.text",
    /**
     * The CSS class that needs to be added to show the popup
     * @type {String}
     */
    POPUP_CLASS_OPEN: "opened",
    /**
     * The element id of the popup
     * @type {String}
     */
    POPUP_ID: "annotation-popup"
  });

  // Icons API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Icon%20Theme%20Application#HJavaScriptAPI)
  define("xwiki-annotate-popup/icons", { 
    icons: [Constants.ANNOTATE_ICON_NAME]
  });

  // Translation API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Localization/#HFromJavaScript)
  define("xwiki-annotate-popup/translation-keys", {
    prefix: "annotations.",
    keys: [Constants.ANNOTATE_TRANSLATION_KEY]
  });

  define("xwiki-annotate-popup", ["xwiki-icon!xwiki-annotate-popup/icons", "xwiki-l10n!xwiki-annotate-popup/translation-keys"], function(icons, l10n) {
    /**
     * Debounces a function
     * @param {Function} func - A function
     * @param {number} delay - Delay time
     * @return {Function} A debounced function
     */
    function debounce(func, delay) {
        let timeout;
        return function (...args) {
            clearTimeout(timeout);
            timeout = setTimeout(() => { func.apply(this, args); }, delay);
        };
    }

    /**
     * Inserts popup to DOM
     *  @return {HTMLElement} The popup element
     */
    function addPopupToDOM() {
        const annotateButton = document.createElement("button");
        annotateButton.classList.add("btn", "btn-default", "btn-xs");
        annotateButton.title = l10n[Constants.ANNOTATE_TRANSLATION_KEY]; // for accessibility
        annotateButton.appendChild(icons[Constants.ANNOTATE_ICON_NAME].render());

        const popup = document.createElement("div");
        popup.id = Constants.POPUP_ID;
        popup.appendChild(annotateButton);

        document.body.appendChild(popup);
        return popup;
    }

    /**
     * Close the popup
     * @param {HTMLElement} popup - The popup element
     */
    const closePopup = (popup) => { popup.classList.remove(Constants.POPUP_CLASS_OPEN) };

    /**
     * Displays the popup near the selected text range
     * @param {HTMLElement} popup - The popup element
     * @param {Selection} selection - A selection
     */
    function openPopup(popup, selection) {
        // use rect of last last line/element, important for correct positioning in multi-line selections
        const rects = selection.getRangeAt(0).getClientRects();
        const rect = rects[rects.length - 1];

        popup.style.top = (rect.top + window.scrollY - popup.offsetHeight - 4) + "px"; // 4px over selection so that it is not "attached"
        popup.style.left = (rect.left + window.scrollX + rect.width - (popup.offsetWidth / 2)) + "px";
        popup.classList.add(Constants.POPUP_CLASS_OPEN);

        // close popup on click away
        const onClickAway = debounce((event) => {
            // Check if the click was within the bounds of the original text selection
            const isClickInsideSelection = rect.left <= event.clientX &&
                                           event.clientX <= rect.right &&
                                           rect.top <= event.clientY &&
                                           event.clientY <= rect.bottom;

            if (!popup.contains(event.target) && !isClickInsideSelection) {
                closePopup(popup);
                document.removeEventListener("click", onClickAway);
            }
        }, 60);
        document.addEventListener("click", onClickAway);

        // close popup when making a new selection
        const onNewSelect = () => {
            closePopup(popup);
            document.removeEventListener("selectionchange", onNewSelect);
        };
        document.addEventListener("selectionchange", onNewSelect);
    }

    /**
     * Register event listeners
     * @param {HTMLElement} wikiContent - The XWiki page container
     * @param {number} popup - The popup element
     */
    function registerListeners(wikiContent, popup) {
        /**
         * Checks the current selection and opens the popup
         */
        function onSelectionChange() {
            const selection = window.getSelection();
            if (!selection || !selection.toString() || !wikiContent.contains(selection.anchorNode)) {
                return;
            }

            openPopup(popup, selection);
        }
        const selectionListener = debounce(onSelectionChange, 800);
        document.addEventListener("selectionchange", selectionListener);

        /**
         * Disables popup when editor is opened
         * @param {MutationRecord[]} mutations - List of mutations on the observed element
         */
        function onClassChange(mutations) {
            for (const mutation of mutations) {
                if (mutation.target.classList.contains("disabled")) {
                    document.removeEventListener("selectionchange", selectionListener);
                } else {
                    document.addEventListener("selectionchange", selectionListener);
                }
            }
         }
        const classObserver = new MutationObserver(onClassChange);
        classObserver.observe(
          document.getElementById("tmAnnotationsTrigger").parentElement, // has class "disabled" if annotations should be disabled
          { attributes: true, attributeFilter: ["class"] }
        );

        // popup listeners
        popup.addEventListener("click", () => {
            closePopup(popup);
            document.dispatchEvent(new KeyboardEvent("keydown", Constants.ANNOTATE_SHORTCUT));
        });
        popup.addEventListener("pointerdown", (event) => { event.preventDefault(); }); // prevent losing focus (the selection) when clicking on popup edges
    }

    /**
     * Initialize AnnotatePopupInline
     * @param {HTMLElement} wikiContent - The XWiki page container
     */
    function init(wikiContent) {
      const popup = addPopupToDOM();
      registerListeners(wikiContent, popup);
    }

    return init;
});

#annotation-popup {
  position: absolute;
  background-color: var(--xwiki-page-content-bg);
  padding: 4px;
  border-radius: 4px;
  box-shadow: 0 1.65px 3px var(--btn-default-border);
  visibility: hidden;
  opacity: 0;
  transition: opacity .2s ease-in;

  &.opened {
    visibility: visible;
    opacity: 1;
  }
}
